 1	import React, { FC } from 'react';
 2	import { Trans } from 'react-i18next';
 3	
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { ListPageBody, ListPageHeader } from '@openshift-console/dynamic-plugin-sdk';
 6	import {
 7	  EmptyState,
 8	  EmptyStateActions,
 9	  EmptyStateBody,
10	  EmptyStateFooter,
11	  EmptyStateHeader,
12	  EmptyStateIcon,
13	  EmptyStateVariant,
14	} from '@patternfly/react-core';
15	import { AddCircleOIcon } from '@patternfly/react-icons';
16	
17	import BootableVolumeAddButton from './BootableVolumeAddButton';
18	
19	type BootableVolumesEmptyStateProps = {
20	  namespace: string;
21	};
22	
23	const BootableVolumesEmptyState: FC<BootableVolumesEmptyStateProps> = ({ namespace }) => {
24	  const { t } = useKubevirtTranslation();
25	
26	  return (
27	    <>
28	      <ListPageHeader title={t('Bootable volumes')} />
29	
30	      <ListPageBody>
31	        <EmptyState variant={EmptyStateVariant.lg}>
32	          <EmptyStateHeader
33	            headingLevel="h4"
34	            icon={<EmptyStateIcon icon={AddCircleOIcon} />}
35	            titleText={<>{t('No bootable volumes found')}</>}
36	          />
37	
38	          <EmptyStateBody>
39	            <Trans ns="plugin__kubevirt-plugin" t={t}>
40	              Click <b>Add bootable volume</b> to add your first bootable volume
41	            </Trans>
42	          </EmptyStateBody>
43	
44	          <EmptyStateFooter>
45	            <EmptyStateActions>
46	              <BootableVolumeAddButton buttonText={t('Add volume')} namespace={namespace} />
47	            </EmptyStateActions>
48	          </EmptyStateFooter>
49	        </EmptyState>
50	      </ListPageBody>
51	    </>
52	  );
53	};
54	
55	export default BootableVolumesEmptyState;

